function handleBooleanDisplay(value) {
	const { tickNoSVG, tickYesSVG } = appsmith.model.icons;
	const TickYesIcon = getSvgFromObj(tickYesSVG);
	const TickNoIcon = getSvgFromObj(tickNoSVG);
	return <span className="tick-icon">{value === "true" ? TickYesIcon : TickNoIcon}</span>
}

function handleNumberDisplay(value, unit) {
	const realValue = unit === "€" ?formatNumber(parseInt(value) / 100) : parseInt(value);
	return `${realValue}${unit}`;
}

function handleStringDisplay(value, responses) {
	if (!responses) return value;
	const responsesMap = JSON.parse(responses);
	return responsesMap[value].text ?? value;
}

function getFeatureValueByName(features, features_label) {
	features = features["options"];
	for (let category of features) {
		for (let option of category["options"]) {
			const { type, label, unit, value, responses } = option;
			if (label == features_label) {
				if (!value) return "-";
				const handlers = {
					default: () => value,
					boolean: () => handleBooleanDisplay(value),
					number: () => handleNumberDisplay(value, unit),
					string: () => handleStringDisplay(value, responses),
				};
				return (handlers[type] || handlers.default)();
			}
		}
	}
	return null;
}

function getFeatureByName(features, features_label) {
	features = features["options"];
	for (let category of features) {
		for (let option of category["options"]) {
			if (option["label"] == features_label) {
				return option;
			}
		}
	}
	return {};
}

function generateOfferGridItemBody(offer, featureName) {
	const featureOption =  getFeatureByName(offer, featureName);

	if (!featureOption || !featureOption.label) {
        return null;
    }
	const icon = appsmith.model.offerOptionsIcons[featureName]
	return (
		<>
        <span className="item-label" style={{ fontSize: "24px", lineHeight: "1" }}>
          {icon}
        </span>
        <span className="item-value">
	      {getFeatureValueByName(offer, featureName)}{offer.unit}
	    </span>
      </>
	) 
}

	function OfferCard(offer) {
		const isChosen = offer.state == "CHOSEN"
		const allOffersShownOptions = appsmith.model.allOffersShownOptions || [];
		return (
			<div className="offer-card" style={isChosen ? { border: "2px solid blue" } : {}}>
			<div className="offer-item first-offer-item">
				<img
src={offer.partner.logo}
alt="Logo partenaire"
className="offer-image"
style={{
			 background: offer.partner.color
			}}
			/>
<div className="offer-description">
	<span className="insurer-name">{offer.partner.name}</span>
<span className="formula-name">{offer.name}</span>
</div>
</div>

<div className="offer-item">
	<div className="offer-grid">
		<div className="offer-grid-item top-left">
			{generateOfferGridItemBody(offer, allOffersShownOptions[0])}
</div>

<div className="separator" id="separator-1"></div>

<div className="offer-grid-item top-right">
	{generateOfferGridItemBody(offer, allOffersShownOptions[1])}
</div>

<div className="separator" id="separator-2"></div>

<div className="offer-grid-item">
	{generateOfferGridItemBody(offer, allOffersShownOptions[2])}
</div>

<div className="separator" id="separator-3"></div>

<div className="offer-grid-item">
	{generateOfferGridItemBody(offer, allOffersShownOptions[3])}
</div>

<div className="separator" id="separator-4"></div>

<div className="offer-grid-item bottom-left">
						{generateOfferGridItemBody(offer, allOffersShownOptions[4])}
					</div>

					<div className="separator" id="separator-5"></div>

					<div className="offer-grid-item bottom-right">
						{generateOfferGridItemBody(offer, allOffersShownOptions[5])}
					</div>

</div>
</div>

<div className="offer-item-vertical-box">
	{offer.is_estimation ?
	 <div className="text-box">
	 <span className="text-top">Tarif sur devis</span>
	 </div>
	 :
	 <>
	 <div className="text-box">
	 <span className="text-top"><b>{offer.price}€</b> /mois</span>
</div>
<div className="text-box">
	<span className="text-bottom" style={{ "color": offer.savingsTextColor }}>
		<b>{offer.savings}€</b> {offer.savingsUnit}
</span>
</div>
</>
}
	</div>

<div className="offer-item">
	<button
className="btn btn-select"
onClick={() => {
	appsmith.triggerEvent("seeOffer", { 'offer': offer })
}}>
	Voir l'offre
</button>
</div>
</div>
);
}

function App() {
	const offers = appsmith.model.offers;
	return (
		<div className="app">
